/**
 * 역 이름으로 SRT 역 코드 조회
 */
export function getSrtStationCode(name: string): string | undefined {
  return SRT_STATION_CODES[name.trim()];
}

/**
 * 역 이름으로 Korail 역 코드 조회
 */
export function getKorailStationCode(name: string): string | undefined {
  return KORAIL_STATION_CODES[name.trim()];
}
